import * as React from "react";
import { act, fireEvent, render } from "@testing-library/react";

import { expectCurrentImageToBe, lightbox } from "./test-utils.js";
import { Inline } from "../../src/plugins/index.js";

const slides = [{ src: "image1" }, { src: "image2" }, { src: "image3" }];

function getContainer() {
  return document.querySelector(".yarl__container") as HTMLElement;
}

function pressArrowLeft() {
  act(() => {
    fireEvent.keyDown(getContainer(), { key: "ArrowLeft" });
  });
  act(vi.runAllTimers);
}

function pressArrowRight() {
  act(() => {
    fireEvent.keyDown(getContainer(), { key: "ArrowRight" });
  });
  act(vi.runAllTimers);
}

function renderLightbox(props?: Parameters<typeof lightbox>[0]) {
  return render(lightbox({ slides, carousel: { finite: true }, ...props }));
}

function renderInlineLightbox(props?: Parameters<typeof lightbox>[0]) {
  return renderLightbox({ plugins: [Inline], ...props });
}

/**
 * Mock getComputedStyle to return "rtl" direction for elements that have
 * a `dir="rtl"` ancestor, since jsdom doesn't support CSS direction inheritance.
 */
function mockComputedStyleRTL() {
  const original = window.getComputedStyle;
  return vi.spyOn(window, "getComputedStyle").mockImplementation((element, pseudoElt) => {
    const result = original(element, pseudoElt);
    if (element instanceof HTMLElement && element.closest("[dir='rtl']")) {
      return new Proxy(result, {
        get(target, prop) {
          if (prop === "direction") return "rtl";
          const value = Reflect.get(target, prop);
          return typeof value === "function" ? value.bind(target) : value;
        },
      });
    }
    return result;
  });
}

function testLTRKeyboardNavigation() {
  it("ArrowRight navigates to the next slide", () => {
    expectCurrentImageToBe("image2");

    pressArrowRight();
    expectCurrentImageToBe("image3");
  });

  it("ArrowLeft navigates to the previous slide", () => {
    expectCurrentImageToBe("image2");

    pressArrowLeft();
    expectCurrentImageToBe("image1");
  });
}

function testRTLKeyboardNavigation() {
  it("ArrowLeft navigates to the next slide", () => {
    expectCurrentImageToBe("image2");

    pressArrowLeft();
    expectCurrentImageToBe("image3");
  });

  it("ArrowRight navigates to the previous slide", () => {
    expectCurrentImageToBe("image2");

    pressArrowRight();
    expectCurrentImageToBe("image1");
  });
}

beforeEach(() => {
  vi.useFakeTimers();
  return () => vi.useRealTimers();
});

describe("RTL", () => {
  describe("LTR (default)", () => {
    beforeEach(() => {
      renderLightbox({ index: 1 });
    });

    testLTRKeyboardNavigation();
  });

  describe("html dir attribute", () => {
    beforeEach(() => {
      document.documentElement.setAttribute("dir", "rtl");
      const spy = mockComputedStyleRTL();

      renderLightbox({ index: 1 });

      return () => {
        document.documentElement.removeAttribute("dir");
        spy.mockRestore();
      };
    });

    testRTLKeyboardNavigation();
  });

  describe("inline dir attribute", () => {
    beforeEach(() => {
      renderInlineLightbox({ inline: { dir: "rtl" }, index: 1 });
    });

    testRTLKeyboardNavigation();
  });

  describe("inline with RTL ancestor", () => {
    beforeEach(() => {
      const spy = mockComputedStyleRTL();

      render(
        React.createElement(
          "div",
          { dir: "rtl" },
          lightbox({ slides, carousel: { finite: true }, plugins: [Inline], index: 1 }),
        ),
      );
      return () => spy.mockRestore();
    });

    testRTLKeyboardNavigation();
  });

  describe("portal container dir attribute", () => {
    beforeEach(() => {
      renderLightbox({ portal: { container: { dir: "rtl" } }, index: 1 });
    });

    testRTLKeyboardNavigation();
  });
});
import * as React from "react";
import { act, screen } from "@testing-library/react";

import Lightbox from "../../src/index.js";

function lightboxRoot() {
  return document.querySelector(".yarl__root");
}

export function lightbox(props?: Parameters<typeof Lightbox>[0]) {
  return <Lightbox open {...props} />;
}

export function querySelector(selector: string) {
  return lightboxRoot()?.querySelector(selector) ?? null;
}

export function findCurrentSlide() {
  return querySelector("div.yarl__slide_current");
}

export function findCurrentImage() {
  return findCurrentSlide()?.querySelector("img")?.src;
}

export function expectCurrentImageToBe(source: string) {
  expect(findCurrentImage()).toContain(source);
}

export function clickButton(name: string) {
  act(() => {
    screen.getByRole("button", { name }).click();
  });
}

export function queryButton(name: string) {
  return screen.queryByRole("button", { name });
}

export function expectToContainButton(name: string) {
  expect(queryButton(name)).toBeInTheDocument();
}

export function expectNotToContainButton(name: string) {
  expect(queryButton(name)).not.toBeInTheDocument();
}

export function expectLightboxToBeOpen() {
  expect(lightboxRoot()).toBeInTheDocument();
}

export function expectLightboxToBeClosed() {
  expect(lightboxRoot()).not.toBeInTheDocument();
}

import * as React from "react";

import { clsx, cssClass } from "../utils.js";
import { useForkRef } from "../hooks/index.js";
import { DocumentContextProvider, RTLContextProvider, useA11yContext } from "../contexts/index.js";

export const LightboxRoot = React.forwardRef<HTMLDivElement, React.ComponentProps<"div">>(function LightboxRoot(
  { className, children, onFocus, onBlur, ...rest },
  ref,
) {
  const nodeRef = React.useRef<HTMLDivElement>(null);
  const [isRTL, setIsRTL] = React.useState(false);
  const { trackFocusWithin } = useA11yContext();

  const detectRTL = React.useCallback((node: HTMLDivElement | null) => {
    if (node) {
      setIsRTL(window.getComputedStyle(node).direction === "rtl");
    }
  }, []);

  return (
    <DocumentContextProvider nodeRef={nodeRef}>
      <RTLContextProvider isRTL={isRTL}>
        <div
          ref={useForkRef(useForkRef(ref, nodeRef), detectRTL)}
          className={clsx(cssClass("root"), className)}
          {...trackFocusWithin(onFocus, onBlur)}
          {...rest}
        >
          {children}
        </div>
      </RTLContextProvider>
    </DocumentContextProvider>
  );
});
